// Returns questions for a subject+chapter, falling back to cross-chapter pool
export function getQuestionsForChapter(subjectId, chapterId) {
  const subjectBank = QUESTION_BANK[subjectId] || {};
  if (chapterId && subjectBank[chapterId]) return subjectBank[chapterId];
  // Flatten all chapters for full-subject tests
  return Object.values(subjectBank).flat();
}

// Fisher-Yates shuffle
export function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}
